// Helper: get topics by block
export const getTopicsByBlock = (blockId) =>
  CURRICULUM.filter(t => t.block === blockId);

// Helper: get unique blocks
export const getBlocks = () => {
  const blocks = new Map();
  CURRICULUM.forEach(t => {
    if (!blocks.has(t.block)) {
      blocks.set(t.block, { id: t.block, name: t.blockName, depth: t.depth });
    }
  });
  return Array.from(blocks.values());
};

// Helper: get topic count per depth
export const getTopicCountByDepth = () => {
  const counts = { LIGHT: 0, MEDIUM: 0, DEEP: 0, DEEPEST: 0 };
  CURRICULUM.forEach(t => counts[t.depth]++);
  return counts;
};
